   */
  constructor(options = {}) {
    this.app_id = options.app_id;
    this.x_api_key = options.x_api_key;
    this.environment = options.environment || 'test';
    this.base_url = options.base_url || 'https://api.prembly.com';
    this.config_id = options.config_id;
    this.user_ref = options.user_ref;

    this._sdk = new PremblyDataVerification({
      app_id: this.app_id,
      x_api_key: this.x_api_key,
      environment: this.environment,
    });

    this._listeners = { success: [], error: [] };
    this._modal = null;
  }

  // ---- Event emitter helpers ------------------------------------------------

  /**
   * Register a listener for "success" or "error" events.
   * @param {"success"|"error"} event
   * @param {Function} callback
   */
  on(event, callback) {
    if (this._listeners[event]) {
      this._listeners[event].push(callback);
    }
    return this; // allow chaining
  }

  _emit(event, data) {
    (this._listeners[event] || []).forEach((cb) => cb(data));
  }

  // ---- Widget UI ------------------------------------------------------------

  /** Open the verification modal. */
  launch() {
    if (this._modal) return; // already open
    this._renderModal();
  }

  _renderModal() {
    // ---- overlay ----
    const overlay = document.createElement('div');
    overlay.id = 'prembly-overlay';
    overlay.style.cssText = `
      position: fixed; inset: 0;
      background: rgba(0,0,0,.55);
      display: flex; align-items: center; justify-content: center;
      z-index: 9999;
    `;

    // ---- modal card ----
    const card = document.createElement('div');
    card.style.cssText = `
      background: #fff; border-radius: 12px; padding: 32px 28px;
      width: min(440px, 94vw); box-shadow: 0 8px 32px rgba(0,0,0,.18);
      font-family: system-ui, sans-serif; position: relative;
    `;

    // close button
    const closeBtn = document.createElement('button');
    closeBtn.textContent = '✕';
    closeBtn.title = 'Close';
    closeBtn.style.cssText = `
      position: absolute; top: 14px; right: 16px;
      background: none; border: none; font-size: 18px;
      cursor: pointer; color: #555; line-height: 1;
    `;
    closeBtn.addEventListener('click', () => this._closeModal());

    // header
    const header = document.createElement('div');
    header.innerHTML = `
      <h2 style="margin:0 0 4px;font-size:1.25rem;color:#1a1a2e;">Identity Verification</h2>
