  _updateFields(type) {
    const container = document.getElementById('prembly-fields');
    if (!container) return;

    const fieldStyle = `
      width:100%;padding:10px;border:1.5px solid #ddd;border-radius:8px;
      margin-bottom:14px;font-size:.9rem;outline:none;box-sizing:border-box
    `;
    const labelStyle = `display:block;margin-bottom:6px;font-size:.875rem;font-weight:600;color:#333`;

    const templates = {
      bvn: `
        <label style="${labelStyle}">BVN Number</label>
        <input id="f-number" type="text" placeholder="e.g. 22222222222"
          style="${fieldStyle}" required />
      `,
      nin: `
        <label style="${labelStyle}">Virtual NIN (vNIN)</label>
        <input id="f-number" type="text" placeholder="e.g. 12345678901234567890"
          style="${fieldStyle}" required />
        <label style="${labelStyle}">Raw NIN</label>
        <input id="f-nin_number" type="text" placeholder="e.g. 12345678901"
          style="${fieldStyle}" required />
      `,
      passport: `
        <label style="${labelStyle}">Passport Number</label>
        <input id="f-number" type="text" placeholder="e.g. A12345678"
          style="${fieldStyle}" required />
        <label style="${labelStyle}">Last Name</label>
        <input id="f-last_name" type="text" placeholder="e.g. Doe"
          style="${fieldStyle}" required />
      `,
    };

    container.innerHTML = templates[type] || '';
  }

  async _handleSubmit(form) {
    const statusEl = form.querySelector('#prembly-status');
    const submitBtn = form.querySelector('[type="submit"]');
    const type = form.querySelector('#prembly-type').value;

    const get = (id) => {
      const el = document.getElementById(id);
      return el ? el.value.trim() : '';
    };

    statusEl.style.color = '#4f46e5';
    statusEl.textContent = 'Verifying… please wait.';
    submitBtn.disabled = true;

    try {
      let result;

      if (type === 'bvn') {
        result = await this._sdk.nigeria.verifyBVN(get('f-number'));
      } else if (type === 'nin') {
        result = await this._sdk.nigeria.verifyVNIN(get('f-number'), get('f-nin_number'));
      } else if (type === 'passport') {
        result = await this._sdk.nigeria.verifyInternationalPassport(get('f-number'), get('f-last_name'));
      } else {
        throw new Error(`Unsupported verification type: ${type}`);
      }

      // Attach widget meta to the result
      const payload = {
        config_id: this.config_id,
        user_ref: this.user_ref,
        verification_type: type,
        result,
      };

      if (result && (result.status === true || result.response_code === '00')) {
        statusEl.style.color = '#16a34a';
        statusEl.textContent = '✔ Verification successful!';
        console.log('[PremblyPass] success', payload);
        this._emit('success', payload);
      } else {
        statusEl.style.color = '#dc2626';
        statusEl.textContent = `✖ Verification failed: ${result?.detail || result?.message || 'Unknown error'}`;
        console.error('[PremblyPass] error', payload);
        this._emit('error', payload);
      }
    } catch (err) {
      const errorPayload = { config_id: this.config_id, user_ref: this.user_ref, error: err.message };
      statusEl.style.color = '#dc2626';
      statusEl.textContent = `✖ Error: ${err.message}`;
      console.error('[PremblyPass] error', errorPayload);
      this._emit('error', errorPayload);
    } finally {
      submitBtn.disabled = false;
    }
  }

  _closeModal() {
    if (this._modal) {
      this._modal.remove();
      this._modal = null;
    }
  }
}

