      <h2 style="margin:0 0 4px;font-size:1.25rem;color:#1a1a2e;">Identity Verification</h2>
      <p style="margin:0 0 20px;font-size:.875rem;color:#666;">
        Powered by <strong>Prembly</strong> &nbsp;|&nbsp;
        Config: <code style="background:#f4f4f4;padding:1px 5px;border-radius:4px">${this.config_id}</code>
      </p>
    `;

    // form
    const form = document.createElement('form');
    form.id = 'prembly-form';
    form.innerHTML = `
      <label style="display:block;margin-bottom:6px;font-size:.875rem;font-weight:600;color:#333">
        Verification Type
      </label>
      <select id="prembly-type" style="width:100%;padding:10px;border:1.5px solid #ddd;border-radius:8px;margin-bottom:16px;font-size:.9rem;outline:none">
        <option value="bvn">BVN (Bank Verification Number)</option>
        <option value="nin">Virtual NIN (vNIN)</option>
        <option value="passport">International Passport</option>
      </select>

      <div id="prembly-fields"></div>

      <button type="submit" style="
        width:100%;padding:12px;background:#4f46e5;color:#fff;
        border:none;border-radius:8px;font-size:1rem;font-weight:600;
        cursor:pointer;margin-top:8px;transition:background .2s
      ">Verify Identity</button>

      <p id="prembly-status" style="margin-top:12px;font-size:.85rem;text-align:center;min-height:20px;"></p>
    `;

    card.appendChild(closeBtn);
    card.appendChild(header);
    card.appendChild(form);
    overlay.appendChild(card);
    document.body.appendChild(overlay);
    this._modal = overlay;

    // render initial fields
    this._updateFields('bvn');

    // react to type changes
    form.querySelector('#prembly-type').addEventListener('change', (e) => {
      this._updateFields(e.target.value);
    });

    // handle submission
    form.addEventListener('submit', async (e) => {
      e.preventDefault();
      await this._handleSubmit(form);
    });
  }

  _updateFields(type) {
    const container = document.getElementById('prembly-fields');
    if (!container) return;

    const fieldStyle = `
      width:100%;padding:10px;border:1.5px solid #ddd;border-radius:8px;
      margin-bottom:14px;font-size:.9rem;outline:none;box-sizing:border-box
    `;
    const labelStyle = `display:block;margin-bottom:6px;font-size:.875rem;font-weight:600;color:#333`;

    const templates = {
      bvn: `
        <label style="${labelStyle}">BVN Number</label>
        <input id="f-number" type="text" placeholder="e.g. 22222222222"
          style="${fieldStyle}" required />
      `,
      nin: `
        <label style="${labelStyle}">Virtual NIN (vNIN)</label>
        <input id="f-number" type="text" placeholder="e.g. 12345678901234567890"
          style="${fieldStyle}" required />
        <label style="${labelStyle}">Raw NIN</label>
        <input id="f-nin_number" type="text" placeholder="e.g. 12345678901"
          style="${fieldStyle}" required />
      `,
      passport: `
        <label style="${labelStyle}">Passport Number</label>
        <input id="f-number" type="text" placeholder="e.g. A12345678"
          style="${fieldStyle}" required />
        <label style="${labelStyle}">Last Name</label>
        <input id="f-last_name" type="text" placeholder="e.g. Doe"
          style="${fieldStyle}" required />
      `,
    };

    container.innerHTML = templates[type] || '';
  }

  async _handleSubmit(form) {
    const statusEl = form.querySelector('#prembly-status');
    const submitBtn = form.querySelector('[type="submit"]');
    const type = form.querySelector('#prembly-type').value;

    const get = (id) => {
      const el = document.getElementById(id);
      return el ? el.value.trim() : '';
    };

    statusEl.style.color = '#4f46e5';
    statusEl.textContent = 'Verifying… please wait.';
    submitBtn.disabled = true;

    try {
      let result;

      if (type === 'bvn') {
        result = await this._sdk.nigeria.verifyBVN(get('f-number'));
      } else if (type === 'nin') {
        result = await this._sdk.nigeria.verifyVNIN(get('f-number'), get('f-nin_number'));
      } else if (type === 'passport') {
        result = await this._sdk.nigeria.verifyInternationalPassport(get('f-number'), get('f-last_name'));
      } else {
        throw new Error(`Unsupported verification type: ${type}`);
      }

      // Attach widget meta to the result
      const payload = {
        config_id: this.config_id,
        user_ref: this.user_ref,
        verification_type: type,
        result,
      };

      if (result && (result.status === true || result.response_code === '00')) {
        statusEl.style.color = '#16a34a';
        statusEl.textContent = '✔ Verification successful!';
        console.log('[PremblyPass] success', payload);
        this._emit('success', payload);
      } else {
        statusEl.style.color = '#dc2626';
        statusEl.textContent = `✖ Verification failed: ${result?.detail || result?.message || 'Unknown error'}`;
        console.error('[PremblyPass] error', payload);
        this._emit('error', payload);
      }
    } catch (err) {
      const errorPayload = { config_id: this.config_id, user_ref: this.user_ref, error: err.message };
      statusEl.style.color = '#dc2626';
      statusEl.textContent = `✖ Error: ${err.message}`;
      console.error('[PremblyPass] error', errorPayload);
      this._emit('error', errorPayload);
    } finally {
      submitBtn.disabled = false;
    }
  }

  _closeModal() {
    if (this._modal) {
      this._modal.remove();
      this._modal = null;
    }
  }
}

// ---------------------------------------------------------------------------
// App entry point
// ---------------------------------------------------------------------------

const PREMBLY_API_KEY = import.meta.env.PREMBLY_API_KEY || '';

// Generate a unique user reference for this session
const user_ref = `user_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;

const premblyPass = new PremblyPass({
  app_id: 'test_app_id',
  x_api_key: PREMBLY_API_KEY,
  environment: 'test',
  base_url: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref,
});

// ---- Event listeners -------------------------------------------------------

premblyPass.on('success', (data) => {
  console.log('Verification SUCCESS:', data);
  displayResult('success', data);
});

premblyPass.on('error', (data) => {
  console.error('Verification ERROR:', data);
  displayResult('error', data);
});

// ---- UI helpers ------------------------------------------------------------

function displayResult(type, data) {
  const container = document.getElementById('result-container');
  const title = document.getElementById('result-title');
  const output = document.getElementById('result-output');

  if (!container || !title || !output) return;

  title.textContent = type === 'success' ? '✔ Verification Successful' : '✖ Verification Failed';
  title.style.color = type === 'success' ? '#16a34a' : '#dc2626';
  output.textContent = JSON.stringify(data, null, 2);
  container.style.display = 'block';
  container.scrollIntoView({ behavior: 'smooth' });
}

// ---- Mount UI --------------------------------------------------------------

document.querySelector('#app').innerHTML = `
  <div class="container">
    <h1>Prembly Identity Verification</h1>
    <p>Click the button below to start the identity verification process.</p>
    <button id="verify-btn" type="button">Start Verification</button>

    <div id="result-container" style="display:none; margin-top: 24px;">
      <h2 id="result-title"></h2>
      <pre id="result-output" style="
        background:#f4f4f4; border-radius:8px; padding:16px;
        overflow-x:auto; font-size:.85rem; line-height:1.5;
        white-space:pre-wrap; word-break:break-all;
      "></pre>
    </div>
  </div>
`;

document.getElementById('verify-btn').addEventListener('click', () => {
  premblyPass.launch();
});

